var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"휴~ 이제 거의 다 둘러본 것 같네.","JPN":"ふう～これで、ほとんど見て回ったか。","ENG":"Whew! I think I've seen most of it now.","TWN":"呼～差不多都看過一遍了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"응. 몬스터들도 이쁘게 잘 나온 것 같아.","JPN":"うん。モンスターも綺麗に仕上がってると思うわ。","ENG":"Yeah. I think the monsters turned out pretty nice.","TWN":"嗯，怪物的呈現也很不錯。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"긴데… 저 몬스터들 정말 괜찮은 것 맞나?","JPN":"せやけど……あのモンスター、ホンマに大丈夫なん？","ENG":"But... ya sure these monsters are okay?","TWN":"不過…怪物真的沒問題嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"프로그램이란 건 아는데, 내 저래 얌전한 몬스터는 처음 본다.","JPN":"プログラムだってわかっとるけど、あんな大人しいモンスターは初めて見た。","ENG":"I know it's a program, but I've seen no monster this passive before.","TWN":"我知道這只是個遊戲，但我沒見過這麼溫馴的怪物欸？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"농장…… 컨텐츠.","JPN":"農場……コンテンツ。","ENG":"Farming... content.","TWN":"農場……系統。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"생포한 몬스터를 양식하며 애완용으로 키워보는….","JPN":"生け捕ったモンスターを養殖して、ペットとして育ててみる……","ENG":"Raising captured monsters as pets...","TWN":"可以將捕捉到的怪物當作寵物飼養…"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"와~ 그럼 혹시 저 애들은 계속 데리고 있을 수 있는 거니?","JPN":"わあ～じゃあ、もしかしてあの子たちはずっと連れていけるの？","ENG":"Wow! So you're telling me that I can take them with me?","TWN":"哇～意思是我可以繼續帶著它們嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 그러니까…… 게임이 너무 본격적이란 의미였어…….","JPN":"あはは、だから……ゲームが本格的過ぎるなあって意味だったの……","ENG":"Ah hah hah, what I meant is... the game's really serious...","TWN":"哈哈哈，我的意思是……這個遊戲很專業呢……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"싫으면 싫다 캐라. 보라 니는 기획 권한도 많다매.","JPN":"イヤならイヤって言いや。シホ、あんたは企画権限も大きいやろ？","ENG":"If ya don't like it, just say so. Bora, you said that you have the authority to make changes, no?","TWN":"不喜歡就說直說唄，寶拉你也是有企劃的權限吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"다인이도 아카데미 이사장쯤 되면 어마어마 한긴데, 맘에 안들면 함 따지기도 하고!","JPN":"タエもアカデミーの理事長となると偉いもんやし、気に入らんかったら追及せな！","ENG":"And Dain, you're the chairwoman of the Academy, which is a huge deal! So just tell 'em what you think!","TWN":"妲茵現在也是個學院的理事長，不喜歡的話說個幾句沒問題吧！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L20_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"그, 그건 권력 남용이잖아 리네야.","JPN":"そ、それは権力の濫用よ、マリちゃん。","ENG":"Th-that's an abuse of power, Rinae.","TWN":"這是濫用職權吧，璃奈。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"이건 공동 개발이니까, 우리 둘의 입맛대로만 개발할 순 없어.","JPN":"これは共同開発なんだから、私たち二人の趣味に合わせて開発するわけにはいかないわ。","ENG":"This is a collaborative effort, so we can't just change everything to our liking.","TWN":"而且既然是共同開發，就不能只照我們自己的喜好去做。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"이 정도의 기술력을 갖춘 곳은 보라네 회사밖에 없었거든.","JPN":"これほどの技術力を持ってるところはシホちゃんの会社しかないし。","ENG":"The only company that has this technology is Bora's.","TWN":"有如此技術力的，也只有寶拉的公司。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"뭐……. 어른의 사정이란 게 골치아프긴 하지.","JPN":"ま……大人の事情って面倒やな。","ENG":"Well... Guess bein' an adult isn't all great, huh?","TWN":"喔……變成大人還真麻煩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"리네야. 묻고 싶은게 있는데….","JPN":"マリちゃん。聞きたいことがあるんだけど……","ENG":"Rinae? I have a question...","TWN":"璃奈，我想問你…"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>혹시… 아직도 찾고 있는 거야?</color>","JPN":"<color=#ffd34c>もしかして……まだ探してるの？</color>","ENG":"<color=#ffd34c>Are you... still searching for it?</color>","TWN":"<color=#ffd34c>你…還在找嗎？</color>"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하하, 평소랑 같다. <color=#ffd34c>쌤</color>을 위한 일이니까.","JPN":"はは、いつもどおりや。<color=#ffd34c>先生</color>のためやからな。","ENG":"Ha ha, it's the same old. 'Cause it's for <color=#ffd34c>Teach</color>.","TWN":"哈哈，老樣子。畢竟是為<color=#ffd34c>老師</color>做的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"마, 걱정마라. 현역 때랑은 다르데이. 위험한 일은 한 개도 없다.\xA0\xA0","JPN":"ま、心配せんといて。現役時代とはちゃう。危険なことはない。\xA0\xA0","ENG":"Hey, don't worry 'about it. It's different from back then. There's nothin' dangerous 'bout it.\xA0\xA0","TWN":"放心，現在已經和當時候不一樣啦，一點都不危險的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"그치만 걱정되는걸. 항상 홀연히 사라지고, 답장도 늦고…….","JPN":"でも心配なの。いつも忽然と姿を消すでしょ、返事も遅いし……","ENG":"But it does worry me. You always suddenly disappear and answer back so late...","TWN":"但我還是有點擔心，你常常突然就消失不見，消息又回得很慢……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"당분간 안 떠날 테니까, 니들은 지금 하는 일만 잘해라.","JPN":"しばらくはここにいるつもりやから、今は自分たちの仕事をちゃんとして。","ENG":"I won't be leavin' anytime soon, so you should focus on what you're doin' right now.","TWN":"我暫時不會離開，你們把現在手邊的事處理好就好。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……얘들아.","JPN":"……みんな。","ENG":"...Girls.","TWN":"你們知道……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"지금의 내한테 가장 소중한 게 뭔지 아나? <color=#ffd34c>바로 니들</color>.","JPN":"今のウチにもっとも大事なのが何なのか、わかるか？　<color=#ffd34c>あんたたち</color>や。","ENG":"Ya know what's the most important thing to me right now? <color=#ffd34c>It's y'all</color>.","TWN":"現在對我而言最重要的是什麼嗎？<color=#ffd34c>就是你們</color>。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이젠 그 어떤 상황이 올지라도…. 내는 무조건 니들이데이.","JPN":"どんな状況になったとしても……ウチは絶対あんたたちを選ぶ。","ENG":"So now, whatever happens... I'm always on your side.","TWN":"現在不管發生什麼事…我都會在你們身邊。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"지금은…… 그냥 즐겁게 있자. 그게 맞지 안긋나……?","JPN":"今は……ただ楽しく過ごそ。それがええやろ……？","ENG":"So at least for now... let's just have some fun. Ain't that right...?","TWN":"我們……現在就開心地玩吧，這樣才對吧……？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};